INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68028201e3c98b0941765f1b', '房子很干净，空间也不错，卫生很好。设施很齐全，特别感谢一下前台Rebecca,是我见过最好的前台工作人员，入住的时候还送了两支花，服务也特别好！停车也是免费。', '["https://dimg04.c-ctrip.com/images/0236112000f65cosw9C37_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235r12000f65ec9h70C9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000f65909s7F6B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235v12000f65jyux0A64_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231j12000f65e544087E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000f65ihy0F557_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-19', '红棉双床套房', '套房', '朋友出游', 79, 0, 8, 8, '["前台服务","卫生状况","公共设施"]'::jsonb, '前台服务', '卫生状况', '公共设施'),
('68028217e3c98b0941765f2d', '这是一篇好评！
环境：我们从地铁站下车，正面看起来感觉是普通五星，一走进去就被壁画震撼到！整个酒店内部装饰很大气有质感，办理入住的时候就一整个期待住了！
设施： 可能定期在翻修换新，房间内部设施没有想象中的那么老旧，还OK，石材也都保养的很好！
服务：最值得夸的就是服务了，从一入住开始，前台接待员Tony小麦很热心的办理了服务，因为我们是两个订单，所以需要合并再操作，整个过程他都很热心帮我们处理问题！我们住了三天，行政酒廊的Carrie和Danli都非常细心，期间我包包落在餐厅，拿到后第二天Carrie还有关心问询，非常暖心。接待处的小洪也很热情！
这次广州游本来在连锁酒店跟老牌五星之间纠结，运气很好选了花园酒店，期间整个入住感受服务体验都为我们这次广州行添了不少高光时刻！
如果你跟我一样出行很看重服务的话，花园真的值得??！', '["https://dimg04.c-ctrip.com/images/0230612000aqjmqwwF687_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000aqjgmf5F7D0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-04', '花园双床房', '双床房', '情侣出游', 368, 0, 6, 9, '["前台服务","整体满意度","交通便利性"]'::jsonb, '前台服务', '整体满意度', '交通便利性'),
('68028227e3c98b0941765f34', '酒店就在地铁口，出行很方便。凌晨入住，酒店前台小钟热情办好了入住。当天赶上水管维修，早上酒店工作人员协调去另外一栋楼的房间洗漱，解决问题很及时。', '["https://dimg04.c-ctrip.com/images/0234t12000bodovc3DC5F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000bodos00C55A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000bodor8m37E9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230112000bodor8w70BD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-17', '花园双床房', '双床房', '家庭亲子', 72, 0, 19, 8, '["交通便利性","前台服务","客房服务"]'::jsonb, '交通便利性', '前台服务', '客房服务'),
('68028227e3c98b0941765f35', '地理位置超级好就在地铁站边上，前台接的的小姐姐Rebecca小钟服务很热情还升级送了早餐，赞了赞了', '["https://dimg04.c-ctrip.com/images/0235112000arrglauFC18_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234512000arrn35t93D3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-14', '花园大床房', '大床房', '商务出差', 49, 0, 10, 8, '["交通便利性","前台服务","餐饮设施"]'::jsonb, '交通便利性', '前台服务', '餐饮设施'),
('68028227e3c98b0941765f36', '虽然来过广州很多次，但是第一次入住花园酒店。就是冲着酒店的悠久历史和人文文化来的。非常感谢协助办理入住的前台工作人员Ken，看到我们有小朋友积极帮我们协调房间，并跑前跑后找经理帮我们升级了房型，而且还很耐心的讲解酒店的历史和文化。很耐心的解答我们的各种问题，而且怕我们找不到电梯，还主动送我们到电梯口！酒店的早餐也非常丰富，而且还是旋转餐厅，可以看到小蛮腰！孩子上午一直在酒店泳池内游泳，水质也很干净，工作人员主动提供的饮料和白水。
入住的整体感觉还是非常不错的，下次有机会还会选择花园酒店！再次感谢前台工作人员Ken，让整个十一的广州假期画上了圆满的句号！', '["https://dimg04.c-ctrip.com/images/0232a12000ce5cmyz6AFF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234512000ce5a528D508_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000ce5dhag4693_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000ce59kgm1A47_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-15', '花园双床房', '双床房', '家庭亲子', 279, 0, 1, 9, '["前台服务","餐饮设施","公共设施"]'::jsonb, '前台服务', '餐饮设施', '公共设施'),
('6802823ce3c98b0941765f46', '交通：酒店位置便利，门口就是地铁口，还有商场，出行便捷
环境：酒店大堂摆设很漂亮，拍照出片，一楼餐厅可以看到瀑布，很棒
卫生：房间干净整洁，打扫及时
服务：态度很棒，5楼的Lola（黄丽相）态度非常好，人也很可爱，每天进出看到都会微笑问候，让我们一家都很开心，打扫客房的男生也很热心，态度非常棒～～得到了酒店小羊，非常感谢～入住十分愉快', '["https://dimg04.c-ctrip.com/images/0232w12000ibmsdjk229B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234j12000ibn6gup8305_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000ibn2x5s9EB9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000ibmvmgyDDCB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000ibne0t1C0D1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-02-05', '花园双床房', '双床房', '家庭亲子', 168, 0, 3, 9, '["交通便利性","前台服务","卫生状况"]'::jsonb, '交通便利性', '前台服务', '卫生状况'),
('6802823ce3c98b0941765f4c', '非常好的入住体验，房间非常有特色，也感谢kiki kamille    会再次入住的', '["https://dimg04.c-ctrip.com/images/0234m12000auxat47F775_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234y12000aux79y3269F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-05', '红棉大床套房', '套房', '情侣出游', 42, 0, 8, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028249e3c98b0941765f53', '非常惊喜又满意的入住体验！自己带儿子入住，意外的升级到套房，还赠送两份早餐，下午茶和晚上happy hour 的餐食，真是不能更幸运啦！感谢Betty热情和体贴！
其次，酒店超美的花园，瀑布，超大的浴缸，舒服的大床，都是完美的完美！
最后，酒店地理位置优越，距离机场不到40公里，酒店对面就是个小商圈，吃饭购物都很方便！下次一定会再来！祝酒店生意兴隆，越来越好！', '["https://dimg04.c-ctrip.com/images/0233512000adsuv0u0BB5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p12000adsvxjq17DB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000adsytdg8944_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000adsxcvj6C4B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000adswr5cD941_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-05', '花园大床房', '大床房', '家庭亲子', 181, 0, 18, 9, '["整体满意度","房间设施","周边配套"]'::jsonb, '整体满意度', '房间设施', '周边配套'),
('68028249e3c98b0941765f54', '前台Billy服务热情专业，给我们升级了非常舒适的房间。整个花园酒店非常有底蕴，细节做得很到位，让人心动，下次来广州还是会继续选择入住', '["https://dimg04.c-ctrip.com/images/0236w12000byvdcq8D395_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000byxm1qb0293_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-21', '花园双床房', '双床房', '家庭亲子', 67, 0, 3, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028253e3c98b0941765f58', '第一次入住花园酒店，酒店环境不错，工作人员服务效率很高，入住当天在停车场不小心遗失钓具，凌晨两三点发现，马上告知前台，半个小时左右前台电话通知有发现疑似物品需去前台确认，马上下楼去前台确认，很是感激那晚酒店值班员工Jay，非常感谢??', '["https://dimg04.c-ctrip.com/images/0236a12000agdwzm11A38_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000agdzxexF93C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232f12000age0dpy28F4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-16', '花园大床房', '大床房', '情侣出游', 117, 0, 7, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028253e3c98b0941765f5a', '非常满意的入住体验！感谢前台龚小姐的接待，事无巨细服务超好！吃的东西也很好', '["https://dimg04.c-ctrip.com/images/0234l12000aqr3keu2285_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000aqr4xg32661_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236r12000aqr8rx16E45_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000aqr18dy5CFE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-06', '粤韵双床套房', '套房', '家庭亲子', 37, 0, 3, 6, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68028254e3c98b0941765f5d', '五一假期预定了花园酒店，入住体验还不错。酒店的小花园很漂亮，房间略小但是干净、安静。走的时候krist小姐姐还给了伴手礼', '["https://dimg04.c-ctrip.com/images/0236i12000b58w9xoF657_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-03', '花园双床房', '双床房', '家庭亲子', 60, 0, 1, 6, '["整体满意度","安静程度","卫生状况"]'::jsonb, '整体满意度', '安静程度', '卫生状况'),
('68028254e3c98b0941765f5e', '一家体验感很好的酒店 帮忙办理入住的Betty小姐姐给我们安排了20层能看到酒店后花园的房间 送给了我们好看的花花以及次日早餐 服务很贴心 离店时kiki小姐姐帮忙办理的退房 送给了我们离店小礼品 服务很周到 荔湾艇位于酒店二楼味道很好也很方便 下次出行再来广州还会选择花园酒店', '["https://dimg04.c-ctrip.com/images/0231312000aqpl04s8F8D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236712000aqpt84k903C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000aqppdr5B70C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-05', '花园双床房', '双床房', '家庭亲子', 139, 0, 3, 9, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('68028254e3c98b0941765f61', '预定的是花园酒店的木棉房，因故换成了粤韵房。接待我们姓刘的女经理十分亲切，及时帮我们解决了问题。粤韵房间很舒适。
    酒店大堂十分喜庆漂亮。
    订房时购买套餐里赠送的行政礼遇十分满意。特别是锦鲤行政酒廊两位帅哥美女（美女是印度籍的外籍人士）的服务十分周到细致。我们住宿了二个晚上，去了三次锦鲤酒廊，他们一直热情服务。必须给予一个大大的赞。
    早餐因为是行政礼遇的涵盖，在二楼荔湾亭，环境十分优雅，菜品很丰富可口，基本都是广州的特色小吃。
    一次十分满意的住宿。
   值得推荐。
设施：木棉房比较陈旧了。
环境：大堂和后花园瀑布特别漂亮
服务：很好
卫生：很好', '["https://dimg04.c-ctrip.com/images/0236u12000an67wm61E87_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000an65r3o0380_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k12000an64p9lEA4D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000an6hvnt612A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235012000an62awj9DD2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000an6p5ofB27D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-10', '红棉大床套房', '套房', '家庭亲子', 291, 0, 10, 9, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('6802825ee3c98b0941765f62', '花园酒店已经不记得住过多少次了，每次只要到广州就会住在这里，房间一如既往的舒适，工作人员热情周到，这次妈妈独自去办入住，受到工作人员Vivia的热情接待，妈妈很开心，一直跟我说花园酒店的服务真好，酒店设施齐全，花园也很美。推荐到广州的朋友，一定要到花园酒店来体验一下。', '["https://dimg04.c-ctrip.com/images/0232m12000bdklvj8CB55_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235012000bdkscryADF5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-08', '花园大床房', '大床房', '家庭亲子', 134, 0, 2, 8, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('6802825ee3c98b0941765f64', '不愧是广州的老牌星级酒店，大堂装修富丽堂皇，办理入住得前台Jessie 很nice，耐心解答我们的疑问，知道有小朋友生日还安排送了我们小点心～
酒店的花园真的美，特别是瀑布位置，晚上自助餐的位置可以看到瀑布，不过要提前去取号，因为位置是根据取号先到先选的。自助晚餐品类不是特别多，但够精，刺身都很新鲜。
我们的自助早餐是酒店二楼的中式餐厅，品种挺多的，味道也不错，服务员的态度很好??', '["https://dimg04.c-ctrip.com/images/0232612000aqpffw57947_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000aqpm1v06B67_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235812000aqpgi221F5F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000aqpgjysD433_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000aqpm5fc860A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236o12000aqpitwj9D73_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236e12000aqpeqjg5BD6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-05', '粤韵双床套房', '套房', '家庭亲子', 192, 0, 5, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('6802826be3c98b0941765f71', '设施：虽然是老牌酒店，重新装修后非常实用舒适，带孩子住红棉大床房非常舒适，空间感好。
卫生：干净整洁。
环境：房间漂亮大气。
服务：不愧是白金五星，前台Ann特别暖心帮我们升级服务，对广州酒店业印象非常好；这次带孩子来房间服务很到位，Tina特别仔细房间服务非常好，下次还住花园酒店！', '["https://dimg04.c-ctrip.com/images/0232x12000i3u699mDBD4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000i3ud290B2E9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000i3udc8y7E24_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000i3tj5wo3DAF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000i3tdlhz0FEE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-27', '红棉大床套房', '套房', '家庭亲子', 142, 0, 7, 9, '["房间设施","前台服务","客房服务"]'::jsonb, '房间设施', '前台服务', '客房服务'),
('6802826be3c98b0941765f74', '环境很好很安静 到酒店的时候办理入住的人很多 后来是大厅的麦经理主动帮我们办理入住 服务态度非常好～下次来还会选择花园酒店入住的～', '["https://dimg04.c-ctrip.com/images/0235y12000ap30a6y5FEA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000ap37gmm7890_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-21', '花园双床房', '双床房', '朋友出游', 65, 0, 1, 7, '["前台服务","安静程度","整体满意度"]'::jsonb, '前台服务', '安静程度', '整体满意度'),
('68028276e3c98b0941765f7c', '住了很多次的酒店，环境不错。出行也方便就在市中心，毕竟老牌酒店了。接待的前台好像叫Rebecca，态度挺好还送了两支花！', '["https://dimg04.c-ctrip.com/images/0236712000bazkwv21C7C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236t12000bazjw25BCE4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z12000bazlb876529_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000bazi3tbAFFD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-27', '红棉大床套房', '套房', '商务出差', 60, 0, 4, 7, '["前台服务","交通便利性","整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度'),
('68028280e3c98b0941765f81', '位置不错，环境绝佳，服务不错，大堂经理很有礼貌，尤其是管家小刘服务太到位了，整体是不错的体验。但是当天办理入住的前台真是太差劲了，已经不是服务好不好的问题，简直是毫无“人性”，下午2点多到酒店，询问了她价格后感觉携程优惠力度还是比较大的，就在携程下了订单，但被告知携程订单要等一个多小时，给她说了孩子还没吃饭能不能提前办理，说不可以。无奈之下，就去问大堂服务人员有没有能吃饭的地方，服务员说暂时没有，但还是很耐心的帮忙找了个很小的地方。后来，几经询问，说没有规定网上订单必须等一个小时，就又去前台询问，她说可以办理，等候是我们自己同意的，真是无语了，简直坏的很。', '["https://dimg04.c-ctrip.com/images/0231f12000ejjioe89C3F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000ejjf1tpA388_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235y12000ejjdhiwB19A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-06-21', '花园双床房', '双床房', '家庭亲子', 281, 0, 6, 9, '["前台服务","整体满意度","退房/入住效率"]'::jsonb, '前台服务', '整体满意度', '退房/入住效率'),
('68028280e3c98b0941765f82', '花园酒店，绝对是我入住过众多星级酒店里的TOP 1，白金五星酒店的名号，名不虚传。
房间宽敞，设施齐全，Mini bar，胶囊咖啡，JBL音响，办公桌，沙发，一应俱全。
当得知入住当天，是我家先生的生日，提前布置好房间，还送了生日蛋糕，非常贴心和暖心。
酒店有4家入选米其林指南的餐厅，各式美食应有尽有。
多谢前台小姐姐Gillian和Betty在入住和离店期间的热情接待，温柔耐心，详细地介绍了酒店的网红打卡点，让我们有了一次美好的度假体验。', '["https://dimg04.c-ctrip.com/images/0231612000c2wwj2v3ED0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000c2wl8t0514C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000c2wo3p890B7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235912000c2wlss6C3A7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000c2wqucp8F10_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234n12000c2x3knqF193_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232e12000c2x3a4yB898_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-06', '红棉大床套房', '套房', '其他', 222, 0, 9, 9, '["整体满意度","房间设施","前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务'),
('68028280e3c98b0941765f84', '酒店环境真的不错，服务态度也很好，住宿环境舒适！再次遇见Maggie还是特别仔细和热情，再次提出表扬！', '["https://dimg04.c-ctrip.com/images/0235l12000aqnxo6tB902_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-05', '红棉大床套房', '套房', '独自旅行', 51, 0, 6, 6, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('6802829be3c98b0941765f98', '多次来广州，第一次入住广州花园酒店，一进门就被大堂绚丽的装饰所吸引，服务人员都面带笑容迎接客人的到来～到前台有序办理入住，我们预订的是普通大床房，办理时还需要等待房间收拾出来，特别需要感谢前台接待我们的服务人员，名字叫梁婉彤，当看到我们四岁的儿子快要睡着了就立即给我们升级了儿童套房，孩子进到房间立即被房间里的游乐设施所吸引，高兴坏了～早餐也很好，外面就是酒店园林还有瀑布，赞??入住期间还参观了属于酒店的博物馆，了解了酒店的历史，广州花园酒店还是邓小平给题的词，很有文化和历史的酒店，1981年建设的到现在感觉都不太落伍，可能是我比较喜欢这类风格吧！总之下次来广州一定会优先选择广州花园酒店', '["https://dimg04.c-ctrip.com/images/0230a12000al699qlF8C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000al5mkns8317_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235v12000al5gyjb1FDD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233x12000al52tvi07AD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000al6ci67960C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000al66n1s3BFE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000al5qztvFD9A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231d12000al5u6p90FCC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-04', '花园大床房', '大床房', '家庭亲子', 296, 0, 14, 9, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('6802829be3c98b0941765f99', '1.地理位置：酒店地理位置出行方便，门口就有等位的出租车，酒店大门口就有地铁站淘金站。
2.服务态度：很棒，特别是帮忙办理入住的Dorn,甜美可爱，服务态度也很好。
3.酒店服务：早自助还有3个不同的餐厅，其中瀑布餐厅环节优美，是偏西式的餐厅。2楼有个荔湾庭偏中式，也不错。下午和晚上还提供茶歇，非常便捷。', '["https://dimg04.c-ctrip.com/images/0233o12000c3cpgttB619_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000c3cpdiiA204_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000c3cinakD140_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000c3cpccv199A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000c3cpkb9395B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000c3cq1cmEE78_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234i12000c3cm25b8951_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000c3cjt079CE7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000c3ct5bu51F6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-08', '花园双床房', '双床房', '家庭亲子', 153, 2, 1, 8, '["交通便利性","前台服务","餐饮设施"]'::jsonb, '交通便利性', '前台服务', '餐饮设施'),
('6802829be3c98b0941765f9c', '酒店很气派，过年时间有骑着大公鸡吹喇叭的人，有吹气球的小丑，酒店位置很棒，酒店里居然有大瀑布和大锦鲤，在这里点名表扬kiki，宝宝爸爸眼镜掉到了鱼池子里，Kiki立马组织帮助打捞，特别棒！酒店也很棒！还有超大泳池', '["https://dimg04.c-ctrip.com/images/0231612000aitn60w89AC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b12000aitjolt5AAB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-27', '城央绿意双床房', '双床房', '家庭亲子', 106, 0, 47, 8, '["公共设施","前台服务","整体满意度"]'::jsonb, '公共设施', '前台服务', '整体满意度'),
('6802829be3c98b0941765f9d', '位置一流！去哪都不远，附近好吃的很多。
设施一流！酒店里就有三个米其林，样样好吃。
服务一流！当天有点小发烧，前台Carol帮忙延后了一小时退房，还让客房服务部送来4瓶水，很贴心温暖。其它部门客房，礼宾，门卫，服务也都很主动。
非常棒的入住体验，下次来一定还住广州花园酒店！
另外，room service点了一碗艇仔粥，应该是荔湾亭出品，是迄今吃到的最好的艇仔粥！', '["https://dimg04.c-ctrip.com/images/0233012000asgo7ek185B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235512000asgpfqm598C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p12000asgtzlb6D44_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236q12000asgqxd06EFE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000asgxtmuC111_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-19', '城央绿意双床房', '双床房', '朋友出游', 183, 0, 4, 9, '["周边配套","前台服务","餐饮设施"]'::jsonb, '周边配套', '前台服务', '餐饮设施'),
('680282a6e3c98b0941765fa6', '房间整洁，工作人员态度好，有礼貌。尤其是前台Doris 和Kiki , 热心服务，帮助我处理了很多问题。推荐', '["https://dimg04.c-ctrip.com/images/0236m12000bis0iz73C6A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-28', '花园双床房', '双床房', '家庭亲子', 54, 0, 1, 7, '["前台服务","整体满意度","卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况'),
('680282b2e3c98b0941765fb1', '老牌五星酒店各方面条件都过硬，下午check in时间略长，前台靓女主动给升级成套房，房间设施很赞。非常感谢前厅小敏Kamille小姐的贴心服务，给我们提供了一些很好的建议和帮助，五星好评。下次来广府还是首选花园酒店。', '["https://dimg04.c-ctrip.com/images/0236r12000ak13umm8860_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000ak18igc18E5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-01', '花园大床房', '大床房', '家庭亲子', 109, 0, 1, 8, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('680282bde3c98b0941765fb2', '设施：很方便
卫生：设施齐全
环境：干净舒适
服务：viria和james的服务非常周到 很不错的入住体验', '["https://dimg04.c-ctrip.com/images/0230x12000j9kwodv78F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000j9kr9uh0DA5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000j9k5erdB317_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-23', '花园大床房', '大床房', '情侣出游', 53, 0, 47, 5, '["整体满意度","房间设施","卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况'),
('680282bde3c98b0941765fb5', '环境，设施一流，服务超一流。体验超好的酒店！退房有钱包遗忘房间了，特别感谢前台小李经理，和另一个小伙联系我确认，同时感谢前台美女们，客房服务，早餐人员细心周到的服务。春节出行，让人确实感到宾至如归的服务！??，好的服务背后，相信一定有好的管理，也是老牌酒店常胜不哀的密决，点赞??????????', '["https://dimg04.c-ctrip.com/images/0233912000aih6n5j2741_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000aih2kyb5FA7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000aih7pgm8EE5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-26', '红棉大床套房', '套房', '家庭亲子', 148, 0, 8, 9, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('680282bde3c98b0941765fb7', 'viria的服务很好，入住体验也很满意，白金大使kamille也很棒，下次还会到这边入住！', '["https://dimg04.c-ctrip.com/images/0236612000b58qq3d3530_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-03', '花园大床房', '大床房', '商务出差', 45, 0, 6, 6, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('680282bde3c98b0941765fba', '环境很好，性价比很高，早餐品种虽然不多但是精致。
设施：床睡着很舒服，枕头确实舒服
卫生：干净，打扫及时
服务：及时响应
环境：花园很美
大堂小何小姐姐热情细心', '["https://dimg04.c-ctrip.com/images/0235612000jloxvq924CE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230o12000jloxgeg3EE3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000jloxz2g8339_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000jlolnw6C119_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-06', '花园大床房', '大床房', '家庭亲子', 80, 0, 5, 7, '["性价比","房间设施","卫生状况"]'::jsonb, '性价比', '房间设施', '卫生状况'),
('680282c8e3c98b0941765fbe', '年后出行，到店已经傍晚了，老牌酒店，大堂还是很气派的。门口的服务生看到客人很有服务意识。到了前台，Billy查询到我们定的房间还不能入住，给我们升级了套房还送了早餐。床垫很舒服，卫生间也很大。当天入住生日，酒店还送了蛋糕，住了2天后又续房了。酒店的早餐环境很棒，可以看到花园的瀑布，餐食就比较普通，我觉得到了广州真的没必要在酒店吃，酒店的桃园馆用餐环境也是一级棒，很有广东的特色，很中式，菜品么真的是不及它的环境，不过服务还是很棒的。所以还是很推荐入住这家酒店，服务非常好，除了餐饮不推荐。', '["https://dimg04.c-ctrip.com/images/0234712000ajmdx3nB160_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235y12000ajmiw5i4E83_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230o12000ajmas3t5B6E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000ajm6vfpB0F5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000ajmb3xfB29F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000ajm6yz530F7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000ajmckc53635_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000ajmecssFA6D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-31', '花园双床房', '双床房', '家庭亲子', 245, 0, 7, 9, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('680282c8e3c98b0941765fbf', '办理入住的时候特别顺畅，感谢Gogo小哥哥的帮助。房间很干净，整体给人感觉特别好，下次来广州还会再来的??楼下的桃园馆餐厅也非常不错', '["https://dimg04.c-ctrip.com/images/0231612000aolqp000D04_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000aolqp021167_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-17', '红棉大床套房', '套房', '商务出差', 66, 0, 4, 7, '["前台服务","卫生状况","整体满意度"]'::jsonb, '前台服务', '卫生状况', '整体满意度'),
('680282c8e3c98b0941765fc1', '花园酒店，白金五星级酒店，这里的员工热情有礼，入住时接待员billy的热情接待办理入住，再到礼宾部经理Tim和John的热情介绍酒店周边景点，酒店娱乐设施，寄存行李服务高效快捷，当客人入住后，礼宾部经理Tim亲自将客人寄存在礼宾部的行李送到客人房间并祝客人有个开心愉快的私人假期。行政酒廊李经理，员工Zoey，印度籍员工Carrily为客人提供人性化的用餐服务，得知客人有老人同行，老人家对于欢乐时光餐点有一些吃不惯，马上为老人家准备了两碗热气腾腾的汤粉，早餐对于客人只是提及一些小建议时，印度籍员工Carrily对于客人的建议及时反馈并处理，得到客人的点赞。晚上房间有点冷，致电总机后15楼服务员得知后立马找来一台暖风机给客人使用，因为匆忙，没来得及记下这位女服务员的名字，不过总体来说，花园的服务的确不错，给客人一种真正回到家的温馨感觉。', '["https://dimg04.c-ctrip.com/images/0233b12000al8ht33CBAD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000al7yhos5026_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000al8l21iAF3A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000al7pokb09FA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000al8it8v64CC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235012000al8vt0f432B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000al8cd272203_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000al7n0ro11E4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231g12000al8ljp2B055_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-04', '红棉大床套房', '套房', '独自旅行', 371, 0, 5, 9, '["前台服务","客房服务","餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施'),
('680282c8e3c98b0941765fc4', '春节期间入住酒店，后花园特别惊艳，大厅布置的喜气洋洋、充满过年气息！使人精神特别愉悦！酒店房间确实有些年代感、但胜在酒店的历史和服务！实名感谢行政酒廊的CARRIE小姐姐服务到位、热情洋溢！还要感谢大堂的小花小姐姐给我们及时解决了加床问题！花园酒店、特别喜欢！会再来哦！', '["https://dimg04.c-ctrip.com/images/0234l12000ailhbwoCD97_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236512000ailh9zcBFBF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-27', '花园行政双床套房', '套房', '家庭亲子', 135, 0, 2, 9, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('680282c8e3c98b0941765fc5', '不错的酒店体验 花园太赞了 服务很棒 下电梯就有EllIE小姐姐可以解决我们的各种疑问', '["https://dimg04.c-ctrip.com/images/0233n12000b658q8k677E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000b65ceyhF0A7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000b65coeo765B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235v12000b65joz1ADCD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-06', '红棉大床套房', '套房', '家庭亲子', 43, 0, 2, 6, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('680282d4e3c98b0941765fc6', '不愧是国内仅有的三家白金五星级酒店之一。虽然有些年头了，但是维护的很不错。大堂金碧辉煌的，随处可见的兰花。酒店园景也超棒。你能相信在广州城中的酒店能有如此美的园景。4楼还有一个酒店自身的博物馆。酒店的服务也很好，每个工作人员都很专业。尤其是前台帮我们办理入住的viria小姐姐。态度特别好，很专业，还给我们升级了房间。房间比较新，应该是新装修过了。同时酒店的早餐也不错，种类多，味道好。酒店整体还是非常推荐的，尤其适合带老人家体验。', '["https://dimg04.c-ctrip.com/images/0231r12000bhsht3w0DBA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000bhskppn9ECC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000bhs0tmsEF72_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000bhrwthpD064_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235r12000bhrpoqcB9E2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000bhsaqo68FF4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-25', '红棉大床套房', '套房', '情侣出游', 216, 0, 9, 9, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('680282d4e3c98b0941765fcb', '房间奢华舒适，干净明亮景观好。设施齐全应有尽有，服务快捷周到，响应迅速，行政酒廊的四位小妹妹Echo和Tina活泼开朗，Cathy笑容甜美，中文很棒，Beryle高挑干练，几位小妹妹业务熟悉，对餐厅出品介绍详尽，也贴心地给出酒店度假游玩的建议，非常感谢，非常满意，有机会再去享受花园酒店的白金五星服务', '["https://dimg04.c-ctrip.com/images/0203912000fd3aaxm7FE8_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0232612000fd28bno455D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000fd2kt6vBA5E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232112000fd2qkfx2BCA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230u12000fd28rq5C49B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236a12000fd38jffF104_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-02', '花园大床房', '大床房', '家庭亲子', 150, 0, 36, 9, '["整体满意度","前台服务","景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向'),
('680282d4e3c98b0941765fcc', '酒店很棒！帮忙登记入住的小邓服务很赞????还免费帮升了房间！酒店的服务小姐姐们都很热情贴心，体验感很好！早餐种类很丰富～游泳也很舒服！下次还来！！！推荐！！！????', '["https://dimg04.c-ctrip.com/images/0233o12000eunr67n41A2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000euntmpg36A8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000eunsz4l616A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000eunzj9fF138_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000eunyuiuACDD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-21', '花园大床房', '大床房', '情侣出游', 84, 0, 20, 8, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('680282d4e3c98b0941765fcf', '特别特别满意，酒店绝美，地理位置优越。办理入住的Mancy 真的是人美服务态度好。详细介绍了酒店环境，还提供了旅游交易。在中秋这个美好的日子，酒店贴心的送上了月饼，还有兔子灯。房间干净整洁，没有干扰的声音，床品也非常舒适。住了2晚，在顶楼旋转餐厅和1楼瀑布餐厅都享用了早餐，餐品高级，心情舒适。还贴心安排了远离地铁的房间，真的是丝毫没有影响，在国庆期间，酒店泳池也开放了。很开心的3天2晚，下次还会入住的。再次感谢热情的Mancy哦，大大的赞??', '["https://dimg04.c-ctrip.com/images/0230m12000cbhoeat0438_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000cbhohal51D1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000cbhucb3BD36_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231o12000cbhqhji143E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000cbht4rc9E70_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000cbhnx8qC318_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-03', '红棉大床套房', '套房', '家庭亲子', 223, 0, 14, 9, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('680282dfe3c98b0941765fd1', '花园酒店性价比非常好，最大亮点是带瀑布的花园，下午坐在瀑布下喝咖啡，逛逛花园全家都很喜欢，三层楼还有酒店的博物馆可以参观，前台的黄先生办理入住的时候非常耐心的介绍了酒店餐饮和服务设施。非常愉快的一次住店经历', '["https://dimg04.c-ctrip.com/images/0235r12000asnk4de09D0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232l12000asns42h9017_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000asnr7b6FC90_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234y12000asnpttfDFFE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000asnlprhD795_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-21', '红棉双床套房', '套房', '家庭亲子', 103, 0, 1, 9, '["性价比","整体满意度","前台服务"]'::jsonb, '性价比', '整体满意度', '前台服务'),
('680282dfe3c98b0941765fd9', '酒店环境很棒 前台的Cathy和yomi服务很好 酒店还有个很大的后花园也很漂亮', '["https://dimg04.c-ctrip.com/images/0201w12000as12b6857F9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-16', '花园行政双床套房', '套房', '商务出差', 40, 0, 5, 6, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('680282eae3c98b0941765fda', '做飞机来的，附近地铁交通非常方便！
酒店设施卫生环境都很好！服务也很不错，有需求可以直接找大堂的小哥哥小姐姐，会很贴心及时的帮助你 顺便要特意感谢行政酒廊的Carrie小姐姐，服务特别好，态度很热情??，下次有机会还会再来的！
也会推荐朋友们来哟', '["https://dimg04.c-ctrip.com/images/0235f12000aijx2353FC0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000aijxbqfF6A4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000aijvmj744FB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231b12000aijvtan5DC3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-26', '城央绿意大床房', '大床房', '家庭亲子', 123, 0, 1, 8, '["交通便利性","前台服务","整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度'),
('680282eae3c98b0941765fdb', '每次入住花园酒店，都会有意外惊喜[呲牙]。始终是老牌五星酒店，服务十分到位。管家部行政副管家-许诗玮Janice小姐，细节处做到十分到位，有问必答，亲力亲为。酒店的荔湾亭，环境优雅，十足旧时荔枝湾涌，小桥、流水、树荫、小艇。至于食品，一如既往的喜欢。由于有老人家，荔湾亭的梁经理特别的细心、特别的照顾。点心主管李师傅很专业，虚心，细心听取客人对食品意见。', '["https://dimg04.c-ctrip.com/images/0231i12000d2memmaC7F4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000d2mhgcn4D72_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000d2mb7b83962_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000d2mb7ba331A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000d2mh4ldBCC3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236u12000d2mcxw74594_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232f12000d2mbb6846A5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-29', '红棉双床套房', '套房', '朋友出游', 177, 0, 25, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('680282eae3c98b0941765fdd', '住宿体验很好，管家Janice服务也非常棒～是很棒的一次旅程！', '["https://dimg04.c-ctrip.com/images/0233012000e6psfwgDE3D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000e6pl6e0E357_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000e6pnwtbDACA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-27', '花园大床房', '大床房', '其他', 31, 0, 3, 4, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('680282eae3c98b0941765fde', '设施：广州老牌酒店，设施维护的不错，一进大门就能感受到花园酒店的厚重感。房价咖啡机等配备齐全，备品很香，不错。但对于花园酒店来说，早餐的品类少，不太符合酒店的定位。
卫生：卫生做的干净，没有可挑剔的。
环境：环境自然不用说，酒店后花园很舒服，坐在酒廊看外面喷泉瀑布，很是惬意。

服务：重点说说服务吧，留下印象最深的是前台宾客服务的Tony，得知我第一次来，详细地介绍了酒店各项服务，房间进行了升级，很热情。酒廊的服务也很不错，主动热情。
但瀑布餐厅的服务相比之下就差很多，7点报房号进入，没人带位，前台不主动。', '["https://dimg04.c-ctrip.com/images/0232812000bnursm73CAC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235612000bnuyaad0643_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000bnuy4sr72A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000bnuxt9lBC5C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000bnv0g6f9EDE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000bnuzl3sCA5E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000bnuw9wr387F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h12000bnuzqqaA57A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000bnuyu0xC856_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-07-15', '城央绿意大床房', '大床房', '独自旅行', 256, 0, 11, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('680282eae3c98b0941765fdf', '酒店员工热情友好，服务专业周到，妥妥的白金五星体验??????尤其是前台接待Ariel，服务非常周到，使我们蜜月旅行的第一站，就感到广州酒店的带给客人的舒适和安心。
酒店的设施完备，除了健身房、游泳池等基本设施外，尤其引人注目的，是几个小酒吧以及夜间的瀑布景致，非常适合度假和放松。
再次感谢前台Ariel热情周到细致的服务。??????', '["https://dimg04.c-ctrip.com/images/0233912000ecvs9rj2E40_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000ecw3zgp5C19_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-07', '花园大床房', '大床房', '情侣出游', 169, 0, 3, 9, '["前台服务","公共设施","整体满意度"]'::jsonb, '前台服务', '公共设施', '整体满意度'),
('680282eae3c98b0941765fe1', '房间很宽敞，酒店整体环境不错，前台小钟服务态度很好  值得点赞??', '["https://dimg04.c-ctrip.com/images/0230a12000b5t49mm5060_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000b5t55o90951_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000b5t3twg5D1B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000b5t07im314C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-05', '红棉大床套房', '套房', '商务出差', 33, 0, 5, 6, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度'),
('680282eae3c98b0941765fe2', '到店后被告知金卡可以免费升级房间，收获惊喜！花园酒店环境优雅安静，房间干净，有设计感，床品舒适，浴缸体验佳，蓝牙音箱很棒。特别表扬前台小贺，服务周到热情！', '["https://dimg04.c-ctrip.com/images/0204812000adbvgr5FA24_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0203j12000adbv6jh3DA1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0200s12000adbvnxeBE78_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0204112000adbu416C5F3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0204f12000adbw0vw776B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-03', '花园大床房', '大床房', '情侣出游', 77, 2, 5, 8, '["房间设施","前台服务","安静程度"]'::jsonb, '房间设施', '前台服务', '安静程度')
